select t.id, case when t.status = 1 then 'Active' when t.status = 2 then 'Pending' when t.status = 3 then 'Suspended' else 'Unknown' end as status_label, coalesce(t.display_name, t.login_name, 'N/A') as resolved_name, nullif(t.error_code, 0) as meaningful_error, iif(t.balance > 0, 'Credit', 'Debit') as balance_type, try_cast(t.raw_value as decimal(18, 4)) as parsed_value, convert(varchar(10), t.created_date, 120) as date_string from dbo.transactions t
